document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("customCursor");if(!e)return;let s=0,o=0,t=0,n=0;const i=.2;document.addEventListener("mousemove",e=>{s=e.clientX,o=e.clientY});function a(){t+=(s-t)*i,n+=(o-n)*i,e.style.left=t+"px",e.style.top=n+"px",requestAnimationFrame(a)}a(),document.addEventListener("mouseleave",()=>{e.classList.add("hidden")}),document.addEventListener("mouseenter",()=>{e.classList.remove("hidden")}),document.addEventListener("mousedown",()=>{e.classList.add("click")}),document.addEventListener("mouseup",()=>{e.classList.remove("click")});const r=document.querySelectorAll('a, button, [role="button"], input, select, textarea');r.forEach(t=>{t.addEventListener("mouseenter",()=>e.classList.add("hover")),t.addEventListener("mouseleave",()=>e.classList.remove("hover"))})})